solutions.javascript:
// Fix the bug by using a regular expression to match the route and access route parameters using req.params
// Solution
function resolveRoute(route) {
  const regex = /^/(\w+)\/(\w+)?$/;
  const match = route.match(regex);
  if (match) {
    const params = { id: match[2] || '' };
    return function(req, res) {
      res.send(`Route found with parameter: ${params.id}`);
    }
  } else {
    return function(req, res) {
      res.send('Route not found');
    }
  }
}
